     1→//! Consensus analysis for multiblock datasets
     2→//!
     3→//! This module implements consensus analysis methods for multiblock data,
     4→//! particularly Consensus PCA (CPCA) which finds common principal components
     5→//! across multiple data blocks.
     6→//!
     7→//! # R Equivalents
     8→//! - `consensus_pca()` - Main consensus analysis function
     9→//! - `consensus_weights()` - Compute block weights for consensus
    10→//! - `consensus_scores()` - Extract consensus scores
    11→
    12→use crate::{
    13→    common_types::{Matrix, Vector},
    14→    errors::MultivariousError,
    15→    pca::pca::{Pca, PcaConfig},
    16→    preprocessing::{Preprocessor, steps::Pipeline},
    17→    projector::{BiProjector, Project, Reconstruct},
    18→    svd::SvdMethod,
    19→};
    20→use ndarray::{Array2, Axis};
    21→use std::collections::HashMap;
    22→
    23→/// Configuration for consensus analysis
    24→#[derive(Debug, Clone)]
    25→pub struct ConsensusConfig {
    26→    /// Number of consensus components to extract
    27→    pub n_components: Option<usize>,
    28→    /// SVD method to use
    29→    pub svd_method: SvdMethod,
    30→    /// Whether to center blocks before analysis
    31→    pub center: bool,
    32→    /// Whether to scale blocks before analysis
    33→    pub scale: bool,
    34→    /// Maximum iterations for consensus weight optimization
    35→    pub max_iterations: usize,
    36→    /// Convergence tolerance
    37→    pub tolerance: f64,
    38→}
    39→
    40→impl Default for ConsensusConfig {
    41→    fn default() -> Self {
    42→        Self {
    43→            n_components: None,
    44→            svd_method: SvdMethod::Full,
    45→            center: true,
    46→            scale: false,
    47→            max_iterations: 100,
    48→            tolerance: 1e-6,
    49→        }
    50→    }
    51→}
    52→
    53→/// Consensus projector for multiblock analysis
    54→///
    55→/// Implements Consensus PCA which finds common principal components
    56→/// across multiple data blocks by iteratively optimizing block weights
    57→/// to maximize consensus.
    58→#[derive(Debug, Clone)]
    59→pub struct ConsensusProjector {
    60→    /// Global consensus model (BiProjector)
    61→    global_model: BiProjector,
    62→    /// Block-specific projectors
    63→    block_models: HashMap<String, BiProjector>,
    64→    /// Block weights (normalized to sum to 1)
    65→    block_weights: HashMap<String, f64>,
    66→    /// Preprocessing pipelines for each block
    67→    preprocessors: HashMap<String, Pipeline>,
    68→    /// Configuration
    69→    config: ConsensusConfig,
    70→    /// Number of iterations used
    71→    iterations_used: usize,
    72→    /// Convergence history
    73→    convergence_history: Vec<f64>,
    74→    /// Cached consensus scores
    75→    consensus_scores: Option<Matrix>,
    76→    /// Cached block scores
    77→    block_scores_cache: HashMap<String, Matrix>,
    78→}
    79→
    80→impl ConsensusProjector {
    81→    /// Create a new consensus projector from multiple data blocks
    82→    pub fn new(
    83→        blocks: &HashMap<String, Matrix>,
    84→        config: ConsensusConfig,
    85→    ) -> Result<Self, MultivariousError> {
    86→        // Validate inputs
    87→        if blocks.is_empty() {
    88→            return Err(MultivariousError::InvalidParameter {
    89→                name: "blocks".to_string(),
    90→                value: "empty".to_string(),
    91→                reason: "At least one block required for consensus analysis".to_string(),
    92→            });
    93→        }
    94→
    95→        // Check that all blocks have the same number of rows
    96→        let n_rows = blocks.values().next().unwrap().nrows();
    97→        for (name, block) in blocks {
    98→            if block.nrows() != n_rows {
    99→                return Err(MultivariousError::DimensionMismatch {
   100→                    expected: n_rows.to_string(),
   101→                    actual: block.nrows().to_string(),
   102→                });
   103→            }
   104→        }
   105→
   106→        // Initialize equal weights
   107→        let n_blocks = blocks.len();
   108→        let initial_weight = 1.0 / n_blocks as f64;
   109→        let mut block_weights = HashMap::new();
   110→        for name in blocks.keys() {
   111→            block_weights.insert(name.clone(), initial_weight);
   112→        }
   113→
   114→        // Create preprocessors for each block
   115→        let mut preprocessors = HashMap::new();
   116→        for name in blocks.keys() {
   117→            let mut pipeline = Pipeline::new();
   118→            if config.center {
   119→                pipeline = pipeline.add(Box::new(crate::preprocessing::Center::new()));
   120→            }
   121→            if config.scale {
   122→                pipeline = pipeline.add(Box::new(crate::preprocessing::Scale::new()));
   123→            }
   124→            preprocessors.insert(name.clone(), pipeline);
   125→        }
   126→
   127→        // Create initial global model
   128→        let concatenated = concatenate_blocks(blocks, &block_weights)?;
   129→        let mut pca_config = PcaConfig::default();
   130→        pca_config.svd_method = config.svd_method.clone();
   131→        if let Some(n_comp) = config.n_components {
   132→            pca_config.projector_config.n_components = Some(n_comp);
   133→        }
   134→        let mut pca = Pca::new(pca_config);
   135→        pca.fit(&concatenated)?;
   136→        let global_model = pca.as_bi_projector();
   137→
   138→        // Initialize with empty block models
   139→        let block_models = HashMap::new();
   140→
   141→        let mut projector = Self {
   142→            global_model,
   143→            block_models,
   144→            block_weights,
   145→            preprocessors,
   146→            config,
   147→            iterations_used: 0,
   148→            convergence_history: Vec::new(),
   149→            consensus_scores: None,
   150→            block_scores_cache: HashMap::new(),
   151→        };
   152→
   153→        // Fit the consensus model
   154→        projector.fit(blocks)?;
   155→
   156→        Ok(projector)
   157→    }
   158→
   159→    /// Fit the consensus model by iteratively optimizing block weights
   160→    pub fn fit(&mut self, blocks: &HashMap<String, Matrix>) -> Result<(), MultivariousError> {
   161→        // Preprocess blocks
   162→        let mut preprocessed_blocks = HashMap::new();
   163→        for (name, block) in blocks {
   164→            let pipeline = self.preprocessors.get_mut(name).unwrap();
   165→            let preprocessed = pipeline.fit_transform(block)?;
   166→            preprocessed_blocks.insert(name.clone(), preprocessed);
   167→        }
   168→
   169→        // Iterative consensus optimization
   170→        let mut prev_weights = self.block_weights.clone();
   171→        
   172→        for iter in 0..self.config.max_iterations {
   173→            // Step 1: Update global model using current weights
   174→            let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
   175→            let mut pca_config = PcaConfig::default();
   176→            pca_config.svd_method = self.config.svd_method.clone();
   177→            if let Some(n_comp) = self.config.n_components {
   178→                pca_config.projector_config.n_components = Some(n_comp);
   179→            }
   180→            let mut pca = Pca::new(pca_config);
   181→            pca.fit(&concatenated)?;
   182→            self.global_model = pca.as_bi_projector();
   183→            
   184→            // Compute and cache consensus scores
   185→            self.consensus_scores = Some(self.global_model.scores(&concatenated)?);
   186→
   187→            // Step 2: Fit block-specific models
   188→            self.block_models.clear();
   189→            self.block_scores_cache.clear();
   190→            for (name, block) in &preprocessed_blocks {
   191→                let mut pca_config = PcaConfig::default();
   192→                pca_config.svd_method = self.config.svd_method.clone();
   193→                if let Some(n_comp) = self.config.n_components {
   194→                    pca_config.projector_config.n_components = Some(n_comp);
   195→                }
   196→                let mut block_pca = Pca::new(pca_config);
   197→                block_pca.fit(block)?;
   198→                let bi_proj = block_pca.as_bi_projector();
   199→                
   200→                // Compute and cache block scores
   201→                let block_scores = bi_proj.scores(block)?;
   202→                self.block_scores_cache.insert(name.clone(), block_scores);
   203→                
   204→                self.block_models.insert(name.clone(), bi_proj);
   205→            }
   206→
   207→            // Step 3: Update block weights based on similarity to global model
   208→            let new_weights = self.compute_consensus_weights(&preprocessed_blocks)?;
   209→            
   210→            // Check convergence
   211→            let weight_change = compute_weight_change(&prev_weights, &new_weights);
   212→            self.convergence_history.push(weight_change);
   213→            
   214→            if weight_change < self.config.tolerance {
   215→                self.iterations_used = iter + 1;
   216→                self.block_weights = new_weights;
   217→                break;
   218→            }
   219→
   220→            prev_weights = new_weights.clone();
   221→            self.block_weights = new_weights;
   222→        }
   223→
   224→        if self.iterations_used == 0 {
   225→            self.iterations_used = self.config.max_iterations;
   226→        }
   227→        
   228→        // Final update of scores with converged weights
   229→        let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
   230→        self.consensus_scores = Some(self.global_model.scores(&concatenated)?);
   231→
   232→        Ok(())
   233→    }
   234→
   235→    /// Compute consensus weights based on similarity to global model
   236→    fn compute_consensus_weights(
   237→        &self,
   238→        blocks: &HashMap<String, Matrix>,
   239→    ) -> Result<HashMap<String, f64>, MultivariousError> {
   240→        let mut weights = HashMap::new();
   241→        let mut total_similarity = 0.0;
   242→
   243→        // Compute similarity of each block's loadings to global loadings
   244→        let global_loadings = self.global_model.v.projection_matrix();
   245→        
   246→        for (name, _) in blocks {
   247→            if let Some(block_model) = self.block_models.get(name) {
   248→                let block_loadings = block_model.v.projection_matrix();
   249→                
   250→                // Compute RV coefficient (matrix correlation)
   251→                let similarity = compute_rv_coefficient(global_loadings, block_loadings)?;
   252→                weights.insert(name.clone(), similarity);
   253→                total_similarity += similarity;
   254→            }
   255→        }
   256→
   257→        // Normalize weights to sum to 1
   258→        if total_similarity > 0.0 {
   259→            for weight in weights.values_mut() {
   260→                *weight /= total_similarity;
   261→            }
   262→        }
   263→
   264→        Ok(weights)
   265→    }
   266→
   267→    /// Get consensus scores (from global model)
   268→    pub fn consensus_scores(&self) -> Option<&Matrix> {
   269→        self.consensus_scores.as_ref()
   270→    }
   271→
   272→    /// Get consensus loadings (from global model)
   273→    pub fn consensus_loadings(&self) -> &Matrix {
   274→        self.global_model.components()
   275→    }
   276→
   277→    /// Get block-specific scores
   278→    pub fn block_scores(&self, block_name: &str) -> Option<&Matrix> {
   279→        self.block_scores_cache.get(block_name)
   280→    }
   281→
   282→    /// Get block weights
   283→    pub fn block_weights(&self) -> &HashMap<String, f64> {
   284→        &self.block_weights
   285→    }
   286→
   287→    /// Get number of iterations used
   288→    pub fn iterations_used(&self) -> usize {
   289→        self.iterations_used
   290→    }
   291→
   292→    /// Get convergence history
   293→    pub fn convergence_history(&self) -> &[f64] {
   294→        &self.convergence_history
   295→    }
   296→
   297→    /// Compute cross-block correlations for a given component
   298→    pub fn cross_block_correlations(&self, component: usize) -> Result<Matrix, MultivariousError> {
   299→        let block_names: Vec<_> = self.block_models.keys().cloned().collect();
   300→        let n_blocks = block_names.len();
   301→        
   302→        if n_blocks == 0 {
   303→            return Err(MultivariousError::InvalidParameter {
   304→                name: "block_models".to_string(),
   305→                value: "empty".to_string(),
   306→                reason: "No block models available".to_string(),
   307→            });
   308→        }
   309→        
   310→        // Create correlation matrix
   311→        let mut corr_matrix = Array2::zeros((n_blocks, n_blocks));
   312→        
   313→        for (i, name_i) in block_names.iter().enumerate() {
   314→            for (j, name_j) in block_names.iter().enumerate() {
   315→                if i <= j {
   316→                    let scores_i = self.block_scores_cache.get(name_i).unwrap();
   317→                    let scores_j = self.block_scores_cache.get(name_j).unwrap();
   318→                    
   319→                    // Check component exists
   320→                    if component >= scores_i.ncols() || component >= scores_j.ncols() {
   321→                        return Err(MultivariousError::InvalidComponentCount(component));
   322→                    }
   323→                    
   324→                    // Extract component scores
   325→                    let comp_i = scores_i.column(component);
   326→                    let comp_j = scores_j.column(component);
   327→                    
   328→                    // Compute correlation
   329→                    let corr = compute_correlation(&comp_i.to_owned(), &comp_j.to_owned())?;
   330→                    corr_matrix[[i, j]] = corr;
   331→                    corr_matrix[[j, i]] = corr;  // Symmetric
   332→                }
   333→            }
   334→        }
   335→        
   336→        Ok(corr_matrix)
   337→    }
   338→
   339→    /// Compute consensus analysis result with full statistics
   340→    pub fn compute_consensus_result(&self) -> Result<ConsensusResult, MultivariousError> {
   341→        let n_components = self.global_model.n_components();
   342→        let mut consensus_stats = Vec::new();
   343→        
   344→        // Compute cross-correlations for first component (for result)
   345→        let cross_correlations = self.cross_block_correlations(0)?;
   346→        
   347→        // Compute statistics for each component
   348→        for comp in 0..n_components {
   349→            let corr_matrix = self.cross_block_correlations(comp)?;
   350→            
   351→            // Extract upper triangle (excluding diagonal)
   352→            let mut correlations = Vec::new();
   353→            for i in 0..corr_matrix.nrows() {
   354→                for j in (i+1)..corr_matrix.ncols() {
   355→                    correlations.push(corr_matrix[[i, j]].abs());
   356→                }
   357→            }
   358→            
   359→            let mean_corr = if !correlations.is_empty() {
   360→                correlations.iter().sum::<f64>() / correlations.len() as f64
   361→            } else {
   362→                1.0  // Single block case
   363→            };
   364→            
   365→            let std_corr = if correlations.len() > 1 {
   366→                let variance = correlations.iter()
   367→                    .map(|&x| (x - mean_corr).powi(2))
   368→                    .sum::<f64>() / (correlations.len() - 1) as f64;
   369→                variance.sqrt()
   370→            } else {
   371→                0.0
   372→            };
   373→            
   374→            let min_corr = correlations.iter().cloned().fold(1.0, f64::min);
   375→            let max_corr = correlations.iter().cloned().fold(0.0, f64::max);
   376→            
   377→            // Get variance explained from global model
   378→            let var_explained = self.global_model.sdev[comp].powi(2);
   379→            
   380→            consensus_stats.push(ConsensusStatistic {
   381→                component: comp,
   382→                variance_explained: var_explained,
   383→                mean_correlation: mean_corr,
   384→                std_correlation: std_corr,
   385→                min_correlation: min_corr,
   386→                max_correlation: max_corr,
   387→            });
   388→        }
   389→        
   390→        Ok(ConsensusResult {
   391→            projector: self.clone(),
   392→            cross_correlations,
   393→            consensus_stats,
   394→        })
   395→    }
   396→}
   397→
   398→/// Compute Pearson correlation between two vectors
   399→fn compute_correlation(x: &Vector, y: &Vector) -> Result<f64, MultivariousError> {
   400→    if x.len() != y.len() {
   401→        return Err(MultivariousError::DimensionMismatch {
   402→            expected: x.len().to_string(),
   403→            actual: y.len().to_string(),
   404→        });
   405→    }
   406→    
   407→    let n = x.len() as f64;
   408→    if n <= 1.0 {
   409→        return Ok(1.0);
   410→    }
   411→    
   412→    let mean_x = x.sum() / n;
   413→    let mean_y = y.sum() / n;
   414→    
   415→    let mut cov = 0.0;
   416→    let mut var_x = 0.0;
   417→    let mut var_y = 0.0;
   418→    
   419→    for i in 0..x.len() {
   420→        let dx = x[i] - mean_x;
   421→        let dy = y[i] - mean_y;
   422→        cov += dx * dy;
   423→        var_x += dx * dx;
   424→        var_y += dy * dy;
   425→    }
   426→    
   427→    let denom = (var_x * var_y).sqrt();
   428→    if denom > 0.0 {
   429→        Ok(cov / denom)
   430→    } else {
   431→        Ok(0.0)
   432→    }
   433→}
   434→
   435→/// Concatenate blocks with optional weighting
   436→fn concatenate_blocks(
   437→    blocks: &HashMap<String, Matrix>,
   438→    weights: &HashMap<String, f64>,
   439→) -> Result<Matrix, MultivariousError> {
   440→    let mut columns = Vec::new();
   441→    
   442→    // Sort blocks by name for consistent ordering
   443→    let mut block_names: Vec<_> = blocks.keys().cloned().collect();
   444→    block_names.sort();
   445→
   446→    for name in block_names {
   447→        if let Some(block) = blocks.get(&name) {
   448→            let weight = weights.get(&name).unwrap_or(&1.0);
   449→            
   450→            // Apply square root of weight to columns (so that squared values give the weight)
   451→            let weighted_block = block * weight.sqrt();
   452→            
   453→            for col in weighted_block.axis_iter(Axis(1)) {
   454→                columns.push(col.to_owned());
   455→            }
   456→        }
   457→    }
   458→
   459→    if columns.is_empty() {
   460→        return Err(MultivariousError::InvalidParameter {
   461→            name: "columns".to_string(),
   462→            value: "empty".to_string(),
   463→            reason: "No columns to concatenate".to_string(),
   464→        });
   465→    }
   466→
   467→    // Stack columns horizontally
   468→    let n_rows = columns[0].len();
   469→    let n_cols = columns.len();
   470→    let mut result = Array2::zeros((n_rows, n_cols));
   471→    
   472→    for (i, col) in columns.into_iter().enumerate() {
   473→        result.column_mut(i).assign(&col);
   474→    }
   475→
   476→    Ok(result)
   477→}
   478→
   479→/// Compute RV coefficient between two matrices (matrix correlation)
   480→fn compute_rv_coefficient(x: &Matrix, y: &Matrix) -> Result<f64, MultivariousError> {
   481→    if x.nrows() != y.nrows() {
   482→        return Err(MultivariousError::DimensionMismatch {
   483→            expected: x.nrows().to_string(),
   484→            actual: y.nrows().to_string(),
   485→        });
   486→    }
   487→
   488→    // RV = trace(X'X * Y'Y) / sqrt(trace((X'X)^2) * trace((Y'Y)^2))
   489→    let xx = x.t().dot(x);
   490→    let yy = y.t().dot(y);
   491→    let xy = xx.dot(&yy);
   492→    
   493→    let numerator = xy.diag().sum();
   494→    let xx_squared = xx.dot(&xx);
   495→    let yy_squared = yy.dot(&yy);
   496→    
   497→    let denominator = (xx_squared.diag().sum() * yy_squared.diag().sum()).sqrt();
   498→    
   499→    if denominator > 0.0 {
   500→        Ok(numerator / denominator)
   501→    } else {
   502→        Ok(0.0)
   503→    }
   504→}
   505→
   506→/// Compute change in weights between iterations
   507→fn compute_weight_change(
   508→    old_weights: &HashMap<String, f64>,
   509→    new_weights: &HashMap<String, f64>,
   510→) -> f64 {
   511→    let mut total_change = 0.0;
   512→    
   513→    for (name, &new_weight) in new_weights {
   514→        if let Some(&old_weight) = old_weights.get(name) {
   515→            total_change += (new_weight - old_weight).abs();
   516→        }
   517→    }
   518→    
   519→    total_change
   520→}
