   550→/// Result of consensus analysis
   551→#[derive(Debug, Clone)]
   552→pub struct ConsensusResult {
   553→    /// The consensus projector
   554→    pub projector: ConsensusProjector,
   555→    /// Cross-block correlation matrix
   556→    pub cross_correlations: Matrix,
   557→    /// Consensus statistics per component
   558→    pub consensus_stats: Vec<ConsensusStatistic>,
   559→}
   560→
   561→/// Statistics for a single consensus component
   562→#[derive(Debug, Clone)]
   563→pub struct ConsensusStatistic {
   564→    /// Component index
   565→    pub component: usize,
   566→    /// Variance explained by this component
   567→    pub variance_explained: f64,
   568→    /// Mean absolute correlation across blocks
   569→    pub mean_correlation: f64,
   570→    /// Standard deviation of correlations
   571→    pub std_correlation: f64,
   572→    /// Minimum correlation across blocks
   573→    pub min_correlation: f64,
   574→    /// Maximum correlation across blocks
   575→    pub max_correlation: f64,
   576→}
