        blocks.insert("b".to_string(), array![[5.0], [6.0]]);

        let mut weights = HashMap::new();
        weights.insert("a".to_string(), 1.0);
        weights.insert("b".to_string(), 1.0);

        let concatenated = concatenate_blocks(&blocks, &weights).unwrap();
        assert_eq!(concatenated.shape(), &[2, 3]);
    }

    #[test]
    fn test_weighted_concatenation() {
        let mut blocks = HashMap::new();
        blocks.insert("a".to_string(), array![[2.0], [2.0]]);
        blocks.insert("b".to_string(), array![[4.0], [4.0]]);

        let mut weights = HashMap::new();
        weights.insert("a".to_string(), 0.25);  // sqrt(0.25) = 0.5
        weights.insert("b".to_string(), 0.25);  // sqrt(0.25) = 0.5

        let concatenated = concatenate_blocks(&blocks, &weights).unwrap();
        // Values should be scaled by sqrt(weight)
        assert!((concatenated[[0, 0]] - 1.0).abs() < 1e-10);
        assert!((concatenated[[0, 1]] - 2.0).abs() < 1e-10);
    }

    #[test]
    fn test_consensus_convergence() {
        // Create blocks with similar structure
        let mut blocks = HashMap::new();
        let block1 = array![
            [1.0, 0.1, 0.2],
            [0.1, 1.0, 0.15],
            [0.2, 0.15, 1.0],
            [0.3, 0.25, 0.9]
        ];
        let block2 = array![
            [0.9, 0.15],
            [0.12, 0.95],
            [0.18, 0.2],
            [0.28, 0.3]
        ];

        blocks.insert("block1".to_string(), block1);
        blocks.insert("block2".to_string(), block2);

        let config = ConsensusConfig {
            n_components: Some(2),
            max_iterations: 10,
