    #[test]
    fn test_consensus_scores_shape() {
        let mut blocks = HashMap::new();
        let n_samples = 10;
        let block1 = Array2::from_shape_fn((n_samples, 3), |(i, j)| (i + j) as f64);
        let block2 = Array2::from_shape_fn((n_samples, 4), |(i, j)| (i * j) as f64);

