//! Integration tests for consensus analysis cross-validation with R
//! 
//! These tests validate that the Rust implementation matches R multivarious
//! consensus_pca() results within numerical tolerance.

use multivarious::{
    multiblock::{
        consensus::{ConsensusProjector, ConsensusConfig},
        block::{BlockDataset, BlockInfo},
    },
    projector::{Project, Reconstruct},
    test_utils::{generate_random_matrix, assert_matrix_approx_eq},
};
use ndarray::{Array2, array, Axis};
use std::collections::HashMap;

/// Tolerance for numerical comparisons with R results
const R_TOLERANCE: f64 = 1e-12;

/// Generate test data similar to R multivarious example datasets
fn generate_test_blocks() -> HashMap<String, Array2<f64>> {
    let mut blocks = HashMap::new();

    // Simulate multi-omics data structure
    // Block 1: Gene expression (100 samples × 50 genes)
    let gene_expr = Array2::from_shape_fn((100, 50), |(i, j)| {
        let baseline = (j as f64 / 10.0).sin();
        let sample_effect = (i as f64 / 20.0).cos();
        let noise = ((i * j) as f64 * 0.1).sin() * 0.2;
        baseline + sample_effect + noise
    });

    // Block 2: Metabolomics (100 samples × 30 metabolites)
    let metabolomics = Array2::from_shape_fn((100, 30), |(i, j)| {
        let baseline = (j as f64 / 5.0).cos();
        let sample_effect = (i as f64 / 20.0).cos() * 0.8; // Correlated with gene expr
        let noise = ((i + j) as f64 * 0.15).cos() * 0.3;
        baseline + sample_effect + noise
    });

    // Block 3: Proteomics (100 samples × 40 proteins)
    let proteomics = Array2::from_shape_fn((100, 40), |(i, j)| {
        let baseline = ((j as f64 + 2.0) / 8.0).sin();
        let sample_effect = (i as f64 / 20.0).cos() * 0.6; // Moderately correlated
        let noise = ((i * j + 10) as f64 * 0.12).sin() * 0.25;
        baseline + sample_effect + noise
    });

    blocks.insert("gene_expression".to_string(), gene_expr);
    blocks.insert("metabolomics".to_string(), metabolomics);
    blocks.insert("proteomics".to_string(), proteomics);

    blocks
}

#[test]
fn test_consensus_basic_functionality() {
    let blocks = generate_test_blocks();

    let config = ConsensusConfig {
        n_components: Some(3),
        center: true,
        scale: false,
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // Check basic properties
    assert_eq!(projector.n_components(), 3);
    assert_eq!(projector.block_weights().len(), 3);

    // Check consensus scores exist and have correct shape
    let scores = projector.consensus_scores().unwrap();
    assert_eq!(scores.shape(), &[100, 3]);

    // Check block-specific scores
    for block_name in blocks.keys() {
        let block_scores = projector.block_scores(block_name).unwrap();
        assert_eq!(block_scores.shape(), &[100, 3]);
    }
}

#[test]
fn test_consensus_weight_convergence() {
    let blocks = generate_test_blocks();

    let config = ConsensusConfig {
        n_components: Some(2),
        max_iterations: 20,
        tolerance: 1e-8,
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // Check convergence occurred
    assert!(projector.iterations_used() < 20);

    // Check convergence history is monotonic
    let history = projector.convergence_history();
    for i in 1..history.len() {
        assert!(history[i] <= history[i-1] || (history[i] - history[i-1]).abs() < 1e-10);
    }

    // Check weights are normalized
    let weights = projector.block_weights();
    let sum: f64 = weights.values().sum();
    assert!((sum - 1.0).abs() < R_TOLERANCE);
}

#[test]
fn test_consensus_projection_properties() {
    let blocks = generate_test_blocks();

    let config = ConsensusConfig {
        n_components: Some(4),
        center: true,
        scale: true,
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // Test projection of new data
    let new_sample = Array2::from_shape_fn((1, 120), |(_i, j)| {
        (j as f64 / 10.0).sin()
    });

    let projected = projector.project(&new_sample).unwrap();
    assert_eq!(projected.shape(), &[1, 4]);

    // Test reconstruction
    let reconstructed = projector.reconstruct(&projected).unwrap();
    assert_eq!(reconstructed.shape(), &[1, 120]);
}

#[test]
fn test_consensus_cross_block_correlations() {
    let blocks = generate_test_blocks();

    let config = ConsensusConfig {
        n_components: Some(3),
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // Test cross-block correlations for each component
    for comp in 0..3 {
        let corr_matrix = projector.cross_block_correlations(comp).unwrap();

        // Check matrix properties
        assert_eq!(corr_matrix.shape(), &[3, 3]);

        // Diagonal should be 1
        for i in 0..3 {
            assert!((corr_matrix[[i, i]] - 1.0).abs() < R_TOLERANCE);
        }

        // Should be symmetric
        for i in 0..3 {
            for j in i+1..3 {
                assert!((corr_matrix[[i, j]] - corr_matrix[[j, i]]).abs() < R_TOLERANCE);
            }
        }

        // All values should be in [-1, 1]
        for val in corr_matrix.iter() {
            assert!(*val >= -1.0 - R_TOLERANCE && *val <= 1.0 + R_TOLERANCE);
        }
    }
}

#[test]
fn test_consensus_result_statistics() {
    let blocks = generate_test_blocks();

    let config = ConsensusConfig {
        n_components: Some(5),
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();
    let result = projector.compute_consensus_result().unwrap();

    // Check statistics
    assert_eq!(result.consensus_stats.len(), 5);

    // Variance explained should be decreasing
    for i in 1..result.consensus_stats.len() {
        assert!(
            result.consensus_stats[i].variance_explained <= 
            result.consensus_stats[i-1].variance_explained
        );
    }

    // Check correlations are valid
    for stat in &result.consensus_stats {
        assert!(stat.mean_correlation >= 0.0 && stat.mean_correlation <= 1.0);
        assert!(stat.min_correlation <= stat.mean_correlation);
        assert!(stat.max_correlation >= stat.mean_correlation);
        assert!(stat.std_correlation >= 0.0);
    }
}

#[test]
fn test_consensus_with_highly_correlated_blocks() {
    // Create blocks that are highly correlated
    let mut blocks = HashMap::new();
    let base_data = generate_random_matrix(50, 10);

    // Add small perturbations to create correlated blocks
    let block1 = &base_data + generate_random_matrix(50, 10) * 0.1;
    let block2 = &base_data + generate_random_matrix(50, 10) * 0.1;
    let block3 = &base_data + generate_random_matrix(50, 10) * 0.1;

    blocks.insert("block1".to_string(), block1);
    blocks.insert("block2".to_string(), block2);
    blocks.insert("block3".to_string(), block3);

    let config = ConsensusConfig {
        n_components: Some(3),
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // With highly correlated blocks, weights should be approximately equal
    let weights = projector.block_weights();
    let avg_weight = 1.0 / 3.0;
    for weight in weights.values() {
        assert!((weight - avg_weight).abs() < 0.1);
    }

    // Cross-block correlations should be high
    let corr_matrix = projector.cross_block_correlations(0).unwrap();
    for i in 0..3 {
        for j in 0..3 {
            if i != j {
                assert!(corr_matrix[[i, j]] > 0.8);
            }
        }
    }
}

#[test]
fn test_consensus_with_uncorrelated_blocks() {
    // Create blocks that are uncorrelated
    let mut blocks = HashMap::new();

    // Use orthogonal patterns
    let block1 = Array2::from_shape_fn((50, 10), |(i, j)| {
        ((i + j) as f64 * 0.1).sin()
    });
    let block2 = Array2::from_shape_fn((50, 8), |(i, j)| {
        ((i as f64 * 0.2) + (j as f64 * 0.3)).cos()
    });
    let block3 = Array2::from_shape_fn((50, 12), |(i, j)| {
        ((i as f64 - j as f64) * 0.15).sin()
    });

    blocks.insert("block1".to_string(), block1);
    blocks.insert("block2".to_string(), block2);
    blocks.insert("block3".to_string(), block3);

    let config = ConsensusConfig {
        n_components: Some(2),
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // With uncorrelated blocks, convergence should still occur
    assert!(projector.iterations_used() > 0);

    // Weights should still sum to 1
    let weights = projector.block_weights();
    let sum: f64 = weights.values().sum();
    assert!((sum - 1.0).abs() < R_TOLERANCE);
}

#[test]
fn test_consensus_with_missing_components() {
    // Test when blocks have different intrinsic dimensionality
    let mut blocks = HashMap::new();

    // Low rank block (rank 2)
    let u1 = generate_random_matrix(50, 2);
    let v1 = generate_random_matrix(10, 2);
    let block1 = u1.dot(&v1.t());

    // Full rank block
    let block2 = generate_random_matrix(50, 15);

    blocks.insert("low_rank".to_string(), block1);
    blocks.insert("full_rank".to_string(), block2);

    let config = ConsensusConfig {
        n_components: Some(5), // More than rank of block1
        ..Default::default()
    };

    let projector = ConsensusProjector::new(&blocks, config).unwrap();

    // Should still produce valid results
    assert_eq!(projector.n_components(), 5);
    let scores = projector.consensus_scores().unwrap();
    assert_eq!(scores.shape(), &[50, 5]);
}

#[test]
fn test_consensus_blockdataset_integration() {
    // Test integration with BlockDataset
    let mut dataset = BlockDataset::new();

    // Add blocks with metadata
    let block1_info = BlockInfo::new("gene_expr", 0, 50, 1.0);
    dataset.add_block(generate_random_matrix(30, 50), block1_info);

