//! Consensus analysis for multiblock datasets
//!
//! This module implements consensus analysis methods for multiblock data,
//! particularly Consensus PCA (CPCA) which finds common principal components
//! across multiple data blocks.
//!
//! # R Equivalents
//! - `consensus_pca()` - Main consensus analysis function
//! - `consensus_weights()` - Compute block weights for consensus
//! - `consensus_scores()` - Extract consensus scores

use crate::{
    common_types::{Matrix, Vector},
    errors::MultivariousError,
    pca::pca::{Pca, PcaConfig},
    preprocessing::{Preprocessor, steps::Pipeline},
    projector::{BiProjector, Project, Reconstruct},
    svd::SvdMethod,
};
use ndarray::{Array2, Axis};
use std::collections::HashMap;

/// Configuration for consensus analysis
#[derive(Debug, Clone)]
pub struct ConsensusConfig {
    /// Number of consensus components to extract
    pub n_components: Option<usize>,
    /// SVD method to use
    pub svd_method: SvdMethod,
    /// Whether to center blocks before analysis
    pub center: bool,
    /// Whether to scale blocks before analysis
    pub scale: bool,
    /// Maximum iterations for consensus weight optimization
    pub max_iterations: usize,
    /// Convergence tolerance
    pub tolerance: f64,
}

impl Default for ConsensusConfig {
    fn default() -> Self {
        Self {
            n_components: None,
            svd_method: SvdMethod::Full,
            center: true,
            scale: false,
            max_iterations: 100,
            tolerance: 1e-6,
        }
    }
}

/// Consensus projector for multiblock analysis
///
/// Implements Consensus PCA which finds common principal components
/// across multiple data blocks by iteratively optimizing block weights
/// to maximize consensus.
#[derive(Debug, Clone)]
pub struct ConsensusProjector {
    /// Global consensus model (BiProjector)
    global_model: BiProjector,
    /// Block-specific projectors
    block_models: HashMap<String, BiProjector>,
    /// Block weights (normalized to sum to 1)
    block_weights: HashMap<String, f64>,
    /// Preprocessing pipelines for each block
    preprocessors: HashMap<String, Pipeline>,
    /// Configuration
    config: ConsensusConfig,
    /// Number of iterations used
    iterations_used: usize,
    /// Convergence history
    convergence_history: Vec<f64>,
    /// Cached consensus scores
    consensus_scores: Option<Matrix>,
    /// Cached block scores
    block_scores_cache: HashMap<String, Matrix>,
}

impl ConsensusProjector {
    /// Create a new consensus projector from multiple data blocks
    pub fn new(
        blocks: &HashMap<String, Matrix>,
        config: ConsensusConfig,
    ) -> Result<Self, MultivariousError> {
        // Validate inputs
        if blocks.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "blocks".to_string(),
                value: "empty".to_string(),
                reason: "At least one block required for consensus analysis".to_string(),
            });
        }

        // Check that all blocks have the same number of rows
        let n_rows = blocks.values().next().unwrap().nrows();
        for (name, block) in blocks {
            if block.nrows() != n_rows {
                return Err(MultivariousError::DimensionMismatch {
                    expected: n_rows.to_string(),
                    actual: block.nrows().to_string(),
                });
            }
        }

        // Initialize equal weights
        let n_blocks = blocks.len();
        let initial_weight = 1.0 / n_blocks as f64;
        let mut block_weights = HashMap::new();
        for name in blocks.keys() {
            block_weights.insert(name.clone(), initial_weight);
        }

        // Create preprocessors for each block
        let mut preprocessors = HashMap::new();
        for name in blocks.keys() {
            let mut pipeline = Pipeline::new();
            if config.center {
                pipeline = pipeline.add(Box::new(crate::preprocessing::Center::new()));
            }
            if config.scale {
                pipeline = pipeline.add(Box::new(crate::preprocessing::Scale::new()));
            }
            preprocessors.insert(name.clone(), pipeline);
        }

        // Create initial global model
        let concatenated = concatenate_blocks(blocks, &block_weights)?;
        let mut pca_config = PcaConfig::default();
        pca_config.svd_method = config.svd_method.clone();
        if let Some(n_comp) = config.n_components {
            pca_config.projector_config.n_components = Some(n_comp);
        }
        let mut pca = Pca::new(pca_config);
        pca.fit(&concatenated)?;
        let global_model = pca.as_bi_projector();

        // Initialize with empty block models
        let block_models = HashMap::new();

        let mut projector = Self {
            global_model,
            block_models,
            block_weights,
            preprocessors,
            config,
            iterations_used: 0,
            convergence_history: Vec::new(),
            consensus_scores: None,
            block_scores_cache: HashMap::new(),
        };

        // Fit the consensus model
        projector.fit(blocks)?;

        Ok(projector)
    }

    /// Fit the consensus model by iteratively optimizing block weights
    pub fn fit(&mut self, blocks: &HashMap<String, Matrix>) -> Result<(), MultivariousError> {
        // Preprocess blocks
        let mut preprocessed_blocks = HashMap::new();
        for (name, block) in blocks {
            let pipeline = self.preprocessors.get_mut(name).unwrap();
            let preprocessed = pipeline.fit_transform(block)?;
            preprocessed_blocks.insert(name.clone(), preprocessed);
        }

        // Iterative consensus optimization
        let mut prev_weights = self.block_weights.clone();

        for iter in 0..self.config.max_iterations {
            // Step 1: Update global model using current weights
            let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
            let mut pca_config = PcaConfig::default();
            pca_config.svd_method = self.config.svd_method.clone();
            if let Some(n_comp) = self.config.n_components {
                pca_config.projector_config.n_components = Some(n_comp);
            }
            let mut pca = Pca::new(pca_config);
            pca.fit(&concatenated)?;
            self.global_model = pca.as_bi_projector();

            // Compute and cache consensus scores
            self.consensus_scores = Some(self.global_model.scores(&concatenated)?);

            // Step 2: Fit block-specific models
            self.block_models.clear();
            self.block_scores_cache.clear();
            for (name, block) in &preprocessed_blocks {
                let mut pca_config = PcaConfig::default();
                pca_config.svd_method = self.config.svd_method.clone();
                if let Some(n_comp) = self.config.n_components {
                    pca_config.projector_config.n_components = Some(n_comp);
                }
                let mut block_pca = Pca::new(pca_config);
                block_pca.fit(block)?;
                let bi_proj = block_pca.as_bi_projector();

                // Compute and cache block scores
                let block_scores = bi_proj.scores(block)?;
                self.block_scores_cache.insert(name.clone(), block_scores);

                self.block_models.insert(name.clone(), bi_proj);
            }

            // Step 3: Update block weights based on similarity to global model
            let new_weights = self.compute_consensus_weights(&preprocessed_blocks)?;

            // Check convergence
            let weight_change = compute_weight_change(&prev_weights, &new_weights);
            self.convergence_history.push(weight_change);

            if weight_change < self.config.tolerance {
                self.iterations_used = iter + 1;
                self.block_weights = new_weights;
                break;
            }

            prev_weights = new_weights.clone();
            self.block_weights = new_weights;
        }

        if self.iterations_used == 0 {
            self.iterations_used = self.config.max_iterations;
        }

        // Final update of scores with converged weights
        let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
        self.consensus_scores = Some(self.global_model.scores(&concatenated)?);

        Ok(())
    }

    /// Compute consensus weights based on similarity to global model
    fn compute_consensus_weights(
        &self,
        blocks: &HashMap<String, Matrix>,
    ) -> Result<HashMap<String, f64>, MultivariousError> {
        let mut weights = HashMap::new();
        let mut total_similarity = 0.0;

        // Compute similarity of each block's loadings to global loadings
        let global_loadings = self.global_model.v.projection_matrix();

        for (name, _) in blocks {
            if let Some(block_model) = self.block_models.get(name) {
                let block_loadings = block_model.v.projection_matrix();

                // Compute RV coefficient (matrix correlation)
                let similarity = compute_rv_coefficient(global_loadings, block_loadings)?;
                weights.insert(name.clone(), similarity);
                total_similarity += similarity;
            }
        }

        // Normalize weights to sum to 1
        if total_similarity > 0.0 {
            for weight in weights.values_mut() {
                *weight /= total_similarity;
            }
        }

        Ok(weights)
    }

    /// Get consensus scores (from global model)
    pub fn consensus_scores(&self) -> Option<&Matrix> {
        self.consensus_scores.as_ref()
    }

    /// Get consensus loadings (from global model)
    pub fn consensus_loadings(&self) -> &Matrix {
        self.global_model.components()
    }

    /// Get block-specific scores
    pub fn block_scores(&self, block_name: &str) -> Option<&Matrix> {
        self.block_scores_cache.get(block_name)
    }

    /// Get block weights
    pub fn block_weights(&self) -> &HashMap<String, f64> {
        &self.block_weights
    }

    /// Get number of iterations used
    pub fn iterations_used(&self) -> usize {
        self.iterations_used
    }

    /// Get convergence history
    pub fn convergence_history(&self) -> &[f64] {
        &self.convergence_history
    }

    /// Compute cross-block correlations for a given component
    pub fn cross_block_correlations(&self, component: usize) -> Result<Matrix, MultivariousError> {
        let block_names: Vec<_> = self.block_models.keys().cloned().collect();
        let n_blocks = block_names.len();

        if n_blocks == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "block_models".to_string(),
                value: "empty".to_string(),
                reason: "No block models available".to_string(),
            });
        }

        // Create correlation matrix
        let mut corr_matrix = Array2::zeros((n_blocks, n_blocks));

        for (i, name_i) in block_names.iter().enumerate() {
            for (j, name_j) in block_names.iter().enumerate() {
                if i <= j {
                    let scores_i = self.block_scores_cache.get(name_i).unwrap();
                    let scores_j = self.block_scores_cache.get(name_j).unwrap();

                    // Check component exists
                    if component >= scores_i.ncols() || component >= scores_j.ncols() {
                        return Err(MultivariousError::InvalidComponentCount(component));
                    }

                    // Extract component scores
                    let comp_i = scores_i.column(component);
                    let comp_j = scores_j.column(component);

                    // Compute correlation
                    let corr = compute_correlation(&comp_i.to_owned(), &comp_j.to_owned())?;
                    corr_matrix[[i, j]] = corr;
                    corr_matrix[[j, i]] = corr;  // Symmetric
                }
            }
        }

        Ok(corr_matrix)
    }

    /// Compute consensus analysis result with full statistics
    pub fn compute_consensus_result(&self) -> Result<ConsensusResult, MultivariousError> {
        let n_components = self.global_model.n_components();
        let mut consensus_stats = Vec::new();

        // Compute cross-correlations for first component (for result)
        let cross_correlations = self.cross_block_correlations(0)?;

        // Compute statistics for each component
        for comp in 0..n_components {
            let corr_matrix = self.cross_block_correlations(comp)?;

            // Extract upper triangle (excluding diagonal)
            let mut correlations = Vec::new();
            for i in 0..corr_matrix.nrows() {
                for j in (i+1)..corr_matrix.ncols() {
                    correlations.push(corr_matrix[[i, j]].abs());
                }
            }

            let mean_corr = if !correlations.is_empty() {
                correlations.iter().sum::<f64>() / correlations.len() as f64
            } else {
                1.0  // Single block case
            };

            let std_corr = if correlations.len() > 1 {
                let variance = correlations.iter()
                    .map(|&x| (x - mean_corr).powi(2))
                    .sum::<f64>() / (correlations.len() - 1) as f64;
                variance.sqrt()
            } else {
                0.0
            };

            let min_corr = correlations.iter().cloned().fold(1.0, f64::min);
            let max_corr = correlations.iter().cloned().fold(0.0, f64::max);

            // Get variance explained from global model
            let var_explained = self.global_model.sdev[comp].powi(2);

            consensus_stats.push(ConsensusStatistic {
                component: comp,
                variance_explained: var_explained,
                mean_correlation: mean_corr,
                std_correlation: std_corr,
                min_correlation: min_corr,
                max_correlation: max_corr,
            });
        }

        Ok(ConsensusResult {
            projector: self.clone(),
            cross_correlations,
            consensus_stats,
        })
    }
}

/// Compute Pearson correlation between two vectors
fn compute_correlation(x: &Vector, y: &Vector) -> Result<f64, MultivariousError> {
    if x.len() != y.len() {
        return Err(MultivariousError::DimensionMismatch {
            expected: x.len().to_string(),
            actual: y.len().to_string(),
        });
    }

    let n = x.len() as f64;
    if n <= 1.0 {
        return Ok(1.0);
    }

    let mean_x = x.sum() / n;
    let mean_y = y.sum() / n;

    let mut cov = 0.0;
    let mut var_x = 0.0;
    let mut var_y = 0.0;

    for i in 0..x.len() {
        let dx = x[i] - mean_x;
        let dy = y[i] - mean_y;
        cov += dx * dy;
        var_x += dx * dx;
        var_y += dy * dy;
    }

    let denom = (var_x * var_y).sqrt();
    if denom > 0.0 {
        Ok(cov / denom)
    } else {
        Ok(0.0)
    }
}

/// Concatenate blocks with optional weighting
fn concatenate_blocks(
    blocks: &HashMap<String, Matrix>,
    weights: &HashMap<String, f64>,
) -> Result<Matrix, MultivariousError> {
    let mut columns = Vec::new();

    // Sort blocks by name for consistent ordering
    let mut block_names: Vec<_> = blocks.keys().cloned().collect();
    block_names.sort();

    for name in block_names {
        if let Some(block) = blocks.get(&name) {
            let weight = weights.get(&name).unwrap_or(&1.0);

            // Apply square root of weight to columns (so that squared values give the weight)
            let weighted_block = block * weight.sqrt();

            for col in weighted_block.axis_iter(Axis(1)) {
                columns.push(col.to_owned());
            }
        }
    }

    if columns.is_empty() {
        return Err(MultivariousError::InvalidParameter {
            name: "columns".to_string(),
            value: "empty".to_string(),
            reason: "No columns to concatenate".to_string(),
        });
    }

    // Stack columns horizontally
    let n_rows = columns[0].len();
    let n_cols = columns.len();
    let mut result = Array2::zeros((n_rows, n_cols));

    for (i, col) in columns.into_iter().enumerate() {
        result.column_mut(i).assign(&col);
    }

    Ok(result)
}

/// Compute RV coefficient between two matrices (matrix correlation)
fn compute_rv_coefficient(x: &Matrix, y: &Matrix) -> Result<f64, MultivariousError> {
    if x.nrows() != y.nrows() {
        return Err(MultivariousError::DimensionMismatch {
            expected: x.nrows().to_string(),
            actual: y.nrows().to_string(),
        });
    }

    // RV = trace(X'X * Y'Y) / sqrt(trace((X'X)^2) * trace((Y'Y)^2))
    let xx = x.t().dot(x);
    let yy = y.t().dot(y);
    let xy = xx.dot(&yy);

    let numerator = xy.diag().sum();
    let xx_squared = xx.dot(&xx);
    let yy_squared = yy.dot(&yy);

    let denominator = (xx_squared.diag().sum() * yy_squared.diag().sum()).sqrt();

    if denominator > 0.0 {
        Ok(numerator / denominator)
    } else {
        Ok(0.0)
    }
}

/// Compute change in weights between iterations
fn compute_weight_change(
    old_weights: &HashMap<String, f64>,
    new_weights: &HashMap<String, f64>,
) -> f64 {
    let mut total_change = 0.0;

    for (name, &new_weight) in new_weights {
        if let Some(&old_weight) = old_weights.get(name) {
            total_change += (new_weight - old_weight).abs();
        }
    }

    total_change
}

impl Project for ConsensusProjector {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.global_model.project(data)
    }

    fn n_components(&self) -> usize {
        self.global_model.n_components()
    }

    fn n_features(&self) -> usize {
        self.global_model.n_features()
    }

    fn is_fitted(&self) -> bool {
        self.global_model.is_fitted()
    }

    fn name(&self) -> &str {
        "ConsensusProjector"
    }
}

impl Reconstruct for ConsensusProjector {
    fn reconstruct(&self, scores: &Matrix) -> Result<Matrix, MultivariousError> {
        self.global_model.reconstruct(scores)
    }
}

/// Result of consensus analysis
#[derive(Debug, Clone)]
pub struct ConsensusResult {
    /// The consensus projector
    pub projector: ConsensusProjector,
    /// Cross-block correlation matrix
    pub cross_correlations: Matrix,
    /// Consensus statistics per component
    pub consensus_stats: Vec<ConsensusStatistic>,
}

/// Statistics for a single consensus component
#[derive(Debug, Clone)]
pub struct ConsensusStatistic {
    /// Component index
    pub component: usize,
    /// Variance explained by this component
    pub variance_explained: f64,
    /// Mean absolute correlation across blocks
    pub mean_correlation: f64,
    /// Standard deviation of correlations
    pub std_correlation: f64,
    /// Minimum correlation across blocks
    pub min_correlation: f64,
    /// Maximum correlation across blocks
    pub max_correlation: f64,
}

