    #[test]
    fn test_cross_block_correlations() {
        // Create blocks with known correlations
        let mut blocks = HashMap::new();
        let n_samples = 50;

        // Create base data
        let base = generate_random_matrix(n_samples, 1);

        // Block1: strongly correlated with base
        let block1 = base.clone() + generate_random_matrix(n_samples, 1) * 0.1;
        let mut block1_full = block1.clone();
        block1_full.append(Axis(1), generate_random_matrix(n_samples, 2).view()).unwrap();

        // Block2: moderately correlated with base
        let block2 = base.clone() + generate_random_matrix(n_samples, 1) * 0.5;
        let mut block2_full = block2.clone();
        block2_full.append(Axis(1), generate_random_matrix(n_samples, 3).view()).unwrap();

        // Block3: uncorrelated with base
        let block3 = generate_random_matrix(n_samples, 4);

        blocks.insert("block1".to_string(), block1_full);
        blocks.insert("block2".to_string(), block2_full);
        blocks.insert("block3".to_string(), block3);

        let config = ConsensusConfig {
            n_components: Some(2),
            center: true,
            ..Default::default()
        };

        let projector = ConsensusProjector::new(&blocks, config).unwrap();

        // Get cross-block correlations for first component
        let corr_matrix = projector.cross_block_correlations(0).unwrap();
        assert_eq!(corr_matrix.shape(), &[3, 3]);

        // Diagonal should be 1
        for i in 0..3 {
            assert!((corr_matrix[[i, i]] - 1.0).abs() < 1e-10);
        }

        // Matrix should be symmetric
        for i in 0..3 {
            for j in i+1..3 {
                assert!((corr_matrix[[i, j]] - corr_matrix[[j, i]]).abs() < 1e-10);
            }
        }
    }

