        let z = y.clone();
        let corr_perfect = compute_correlation(&y, &z).unwrap();
        assert!((corr_perfect - 1.0).abs() < 1e-10);

        // Test negative correlation
        let neg_y = -&y;
        let corr_neg = compute_correlation(&y, &neg_y).unwrap();
        assert!((corr_neg + 1.0).abs() < 1e-10);
    }

    #[test]
    fn test_consensus_with_different_svd_methods() {
        let mut blocks = HashMap::new();
        blocks.insert("A".to_string(), generate_random_matrix(50, 10));
        blocks.insert("B".to_string(), generate_random_matrix(50, 8));

        // Test with different SVD methods
        for svd_method in &[SvdMethod::Full, SvdMethod::Thin, SvdMethod::Truncated(3)] {
            let config = ConsensusConfig {
                n_components: Some(3),
                svd_method: svd_method.clone(),
                ..Default::default()
            };

            let projector = ConsensusProjector::new(&blocks, config).unwrap();
            let scores = projector.consensus_scores().unwrap();
            assert_eq!(scores.shape(), &[50, 3]);
        }
    }
}

